 1→export function formatCurrency(value: number): string {
 2→  return new Intl.NumberFormat('en-US', {
 3→    style: 'currency',
 4→    currency: 'USD',
 5→    maximumFractionDigits: 2,
 6→  }).format(Number.isFinite(value) ? value : 0);
 7→}
