 9→export function formatDate(isoString?: string | null): string {
10→  if (!isoString) {
11→    return 'Not set';
12→  }
13→
14→  return new Intl.DateTimeFormat('en-US', {
15→    month: 'short',
16→    day: 'numeric',
17→    year: 'numeric',
18→  }).format(new Date(isoString));
19→}
