262→export function createCartItemFromVaultItem(
263→  vault: Vault,
264→  itemId: string,
265→  quantity: number,
266→  selectedStore?: string | null
267→): CartItem {
268→  const item = getItemById(vault, itemId);
269→  if (!item) {
270→    throw new Error(`Item ${itemId} not found`);
271→  }
272→
273→  const plannedStore = selectedStore ?? item.priceOptions[0]?.store ?? vault.stores[0]?.name ?? 'Unknown Store';
274→
275→  return {
276→    id: createId('cartItem'),
277→    addedAt: new Date().toISOString(),
278→    itemId,
279→    quantity,
280→    isFulfilled: false,
281→    isSkippedDuringShopping: false,
282→    plannedStore,
283→    plannedPrice: getCurrentPrice(item, plannedStore),
284→    plannedUnit: getCurrentUnit(item, plannedStore),
285→    actualStore: null,
286→    actualPrice: null,
287→    actualQuantity: null,
288→    actualUnit: null,
